  if (sel) p = document.querySelector(sel);
  if (!p) {
    const container = btn.closest('form, .field, .wrapper, .container, article, section') || document;
    p = container.querySelector('p');
  }
  if (!p) return;

  const text = (p.textContent || '').trim();
  if (!text) return;

  try {
    await navigator.clipboard.writeText(text);
  } catch (_) {
    const ta = document.createElement('textarea');
    ta.value = text;
    ta.setAttribute('readonly', '');
    ta.style.position = 'fixed';
    ta.style.left = '-9999px';
    document.body.appendChild(ta);
    ta.select();
    document.execCommand('copy');
    document.body.removeChild(ta);
  }

  const prev = btn.getAttribute('data-prev-label');
  if (!prev) btn.setAttribute('data-prev-label', btn.textContent);
  btn.textContent = 'Copied';
  setTimeout(() => {
    const old = btn.getAttribute('data-prev-label');
    if (old) btn.textContent = old;
  }, 1200);
