const crypto = require('crypto');

function decryptAes256HexCiphertext(hexCiphertext, passphrase) {
  const buf = Buffer.from(hexCiphertext, 'hex');
  if (buf.length < 16 + 16) throw new Error('Ciphertext too short');

  const iv = buf.subarray(0, 16);
  const ciphertext = buf.subarray(16, buf.length - 16);
  const tag = buf.subarray(buf.length - 16);

  const key = crypto.createHash('sha256').update(String(passphrase), 'utf8').digest(); // 32 bytes
  const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv);
  decipher.setAuthTag(tag);

  const plaintext = Buffer.concat([decipher.update(ciphertext), decipher.final()]);
  return plaintext.toString('utf8');
}

