const tls = require('tls');
const net = require('net');

function createTlsStreamPair(opts = {}) {
  const {
    serverOptions = {},
    clientOptions = {},
    serverPort = 0,
    host = '127.0.0.1',
    serverHost = host,
    clientHost = host,
    serverKey,
    serverCert,
    clientKey,
    clientCert,
    ca,
    rejectUnauthorized = true
  } = opts;

  const server = tls.createServer({
    key: serverKey,
    cert: serverCert,
    ca,
    requestCert: !!ca,
    rejectUnauthorized: !!ca ? rejectUnauthorized : false,
    ...serverOptions
  });

  const clearServer = net.createServer();
  const clearClient = net.createConnection({ host: clientHost, port: serverPort });

  return new Promise((resolve, reject) => {
    server.on('error', reject);
    clearServer.on('error', reject);

    clearServer.listen(serverPort, host, () => {
      const port = clearServer.address().port;

      const client = tls.connect({
        host: clientHost,
        port,
        key: clientKey,
        cert: clientCert,
        ca,
        rejectUnauthorized: !!ca ? rejectUnauthorized : false,
        ...clientOptions
      });

      server.listen(port, host, () => {
        // no-op; server is already listening on same port for TLS
      });

      server.once('secureConnection', (tlsServerSocket) => {
        const clearServerSocket = clearServer.once('connection', () => {});
        // Bridge cleartext <-> TLS
        clearServer.once('connection', (cs) => {
          cs.pipe(tlsServerSocket);
          tlsServerSocket.pipe(cs);
          resolve({
            encrypted: { client, server: tlsServerSocket },
            cleartext: { client: clearClient, server: cs }
          });
        });
      });

      client.once('error', reject);
      clearClient.once('error', reject);
    });
  });
}

