function normalizeAbsoluteUrl(input) {
  const url = new URL(input, 'http://example.invalid');
  if (!/^[a-zA-Z][a-zA-Z0-9+.-]*$/.test(url.protocol.replace(':', ''))) {
    throw new Error('Invalid URL protocol');
  }
  if (url.protocol === 'http:' && url.host === 'example.invalid') {
    throw new Error('URL must be absolute (include protocol and host)');
  }
  const protocol = url.protocol.toLowerCase();
  const host = url.host.toLowerCase();
  const pathname = url.pathname || '/';
  const search = url.search || '';
  return `${protocol}//${host}${pathname}${search}`;
}
