class ScrollCapture extends React.Component {
  constructor(props) {
    super(props);
    this.prevScrollY = null;
    this.prevScrollX = null;
  }

  getSnapshotBeforeUpdate() {
    const el = document.scrollingElement || document.documentElement;
    this.prevScrollY = el ? el.scrollTop : window.pageYOffset;
    this.prevScrollX = el ? el.scrollLeft : window.pageXOffset;
    return { y: this.prevScrollY, x: this.prevScrollX };
  }

  componentDidUpdate(prevProps, prevState, snapshot) {
    if (this.props.onScrollBeforeUpdate) {
      this.props.onScrollBeforeUpdate({
        prevProps,
        prevState,
        scroll: snapshot || { y: this.prevScrollY, x: this.prevScrollX },
      });
    }
  }

  render() {
    return this.props.children || null;
  }
}

export default ScrollCapture;
