function evaluateExpression(expr) {
  if (typeof expr !== 'string') throw new TypeError('Expression must be a string');
  const s = expr.replace(/\s+/g, '');
  if (!s) throw new Error('Empty expression');
  if (/[^0-9+\-*/().]/.test(s)) throw new Error('Invalid characters');
  if (/(\.\d|\d\.)/.test(s)) throw new Error('Invalid number format');
  if (/\/0(?![0-9.])/.test(s)) throw new Error('Division by zero');
  const tokens = s.match(/\d+|[()+\-*/]/g);
  if (!tokens) throw new Error('Invalid expression');

  const prec = { '+': 1, '-': 1, '*': 2, '/': 2 };
  const ops = [];
  const out = [];

  for (let i = 0; i < tokens.length; i++) {
    let t = tokens[i];
    if (/^\d+$/.test(t)) {
      out.push(Number(t));
      continue;
    }
    if (t === '(') {
      ops.push(t);
      continue;
    }
    if (t === ')') {
      while (ops.length && ops[ops.length - 1] !== '(') out.push(ops.pop());
      if (!ops.length) throw new Error('Mismatched parentheses');
      ops.pop();
      continue;
    }
    if (t === '+' || t === '-' || t === '*' || t === '/') {
      // handle unary +/-
      const prev = tokens[i - 1];
      if ((t === '+' || t === '-') && (i === 0 || (prev && (prev === '(' || prev === '+' || prev === '-' || prev === '*' || prev === '/')))) {
        out.push(0);
      }
      while (ops.length) {
        const top = ops[ops.length - 1];
        if (top === '(') break;
        if (prec[top] >= prec[t]) out.push(ops.pop());
        else break;
      }
      ops.push(t);
      continue;
    }
    throw new Error('Invalid token');
  }

  while (ops.length) {
    const op = ops.pop();
    if (op === '(' || op === ')') throw new Error('Mismatched parentheses');
    out.push(op);
  }

  const stack = [];
  for (const item of out) {
    if (typeof item === 'number') stack.push(item);
    else {
      const b = stack.pop();
      const a = stack.pop();
      if (a === undefined || b === undefined) throw new Error('Invalid expression');
      switch (item) {
        case '+': stack.push(a + b); break;
        case '-': stack.push(a - b); break;
        case '*': stack.push(a * b); break;
        case '/': stack.push(a / b); break;
      }
    }
  }
  if (stack.length !== 1) throw new Error('Invalid expression');
  const res = stack[0];
  if (!Number.isFinite(res)) throw new Error('Result is not finite');
  return res;
}
