function parseQueryString(qs) {
  if (typeof qs !== 'string') return {};
  let s = qs.trim();
  if (s.startsWith('?')) s = s.slice(1);
  if (!s) return {};
  const out = {};
  for (const part of s.split('&')) {
    if (!part) continue;
    const idx = part.indexOf('=');
    const key = decodeURIComponent((idx === -1 ? part : part.slice(0, idx)).replace(/\+/g, ' '));
    const valRaw = idx === -1 ? '' : part.slice(idx + 1);
    const val = decodeURIComponent(valRaw.replace(/\+/g, ' '));
    out[key] = val;
  }
  return out;
}

