function parseTlsSubject(subject) {
  if (subject == null) return {};
  subject = String(subject).trim();
  if (!subject) return {};

  const out = {};
  const parts = subject.replace(/^\/+/, '').split('/');

  for (const part of parts) {
    if (!part) continue;
    const i = part.indexOf('=');
    const key = (i === -1 ? part : part.slice(0, i)).trim();
    const val = (i === -1 ? '' : part.slice(i + 1)).trim();
    if (!key) continue;

    if (Object.prototype.hasOwnProperty.call(out, key)) {
      if (Array.isArray(out[key])) out[key].push(val);
      else out[key] = [out[key], val];
    } else {
      out[key] = val;
    }
  }

  return out;
}

