export function createSecureTLSStreamPair() {
  // Create a pair of connected sockets
  const server = net.createServer();
  const serverSocket = new Promise((resolve) => {
    server.on('connection', (socket) => {
      resolve(socket);
    });
  });

  // Start server on random port
  server.listen(0, '127.0.0.1', async () => {
    const port = server.address().port;

    // Create client socket
    const clientSocket = net.createConnection(port, '127.0.0.1');

    // Get the server socket
    const sSocket = await serverSocket;

    // Create TLS server options
    const serverOptions = {
      key: fs.readFileSync('server.key'),
      cert: fs.readFileSync('server.cert'),
    };

    // Upgrade server socket to TLS (encrypted channel)
    const tlsServerStream = tls.createSecureContext(serverOptions);
    const encryptedStream = tls.createSecureContext(serverOptions);

    // Create TLS streams
    const tlsServer = new tls.TLSSocket(sSocket, {
      isServer: true,
      secureContext: tlsServerStream,
    });

    const tlsClient = tls.connect({
      socket: clientSocket,
      rejectUnauthorized: false,
    });

    // Return both streams
    return {
      encryptedStream: tlsServer,
      cleartextStream: tlsClient,
      cleanup: () => {
        server.close();
        tlsServer.destroy();
        tlsClient.destroy();
      },
    };
