function createTLSPair(tlsOptions = {}) {
  const { pipe: _, ...secureOptions } = tlsOptions;

  const { encrypted, cleartext } = createTLSStreamPair({
    isServer: tlsOptions.isServer || false,
    requestCert: tlsOptions.requestCert || false,
    rejectUnauthorized: tlsOptions.rejectUnauthorized !== false,
    ...secureOptions
  });

  encrypted.on('error', (err) => cleartext.emit('error', err));
  cleartext.on('error', (err) => encrypted.emit('error', err));

  return { encrypted, cleartext };
}

